var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대들의 주인은 오직 고통 받는 이들일지니, 비통한 목소리를 대신하여 이 영광된 의식을 거행한다.","JPN":"そなたたちの主は苦しみに満ちた者たちのみ。悲痛な声に代わり、この栄光なる儀式を執り行おう。","ENG":"You serve no one but the afflicted. I hereby officiate this honorable ceremony on behalf of everyone who's suffering.","TWN":"你們的主人是那些受苦的人，我在此代替那些哀痛的聲音，舉行這榮耀的儀式。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"성좌의 광명을 따르며 만인을 지키기로 맹세할 자, 누구인가?","JPN":"星座の光明に従い、万人を守ると誓う者は誰だ。","ENG":"Who pledges today to follow the radiance of the constellations and protect humanity?","TWN":"跟從星座之光，宣示要守護萬民的人，是誰？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에스테로사, 정의로운 별의 인도로 이 자리에 섰습니다.","JPN":"エステロサ、正義なる星の導きよりこの場に辿り着きました。","ENG":"I, Esterosa, stand here under the guidance of the righteous Stars.","TWN":"我 艾斯特洛索，跟從正義之星的引導站立在這位置上。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대는 그대의 주인에게 무엇을 맹세하겠는가?","JPN":"そなたはそなたの主に何を誓うか。","ENG":"What do you pledge to your masters today?","TWN":"你要對你的主人宣示什麼誓詞？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"적막한 밤의 평화. 별처럼 빛나는 희망. 그리고 내일 새벽이 오리라는 믿음을 맹세합니다.","JPN":"寂寞たる夜の平和。星のごとく光る希望。そして次の夜明けが訪れると信じる心を誓います。","ENG":"The peace of a quiet night. Hope that shines like the stars. And the promise of a new dawn.","TWN":"我宣示，寂靜的夜晚中有和平，希望如星閃耀，以及黎明必將到來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"저……. 저 계집애, 방금 뭐라고 한 거야?","JPN":"あ……あの女、今なんてこと言ったんだ？","ENG":"That... That brat. What did she just say?","TWN":"那……那個丫頭說什麼？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"참아. 아직 예식이 끝나지 않았어.","JPN":"落ち着け。まだ儀式の途中だぞ。","ENG":"Easy. The ceremony isn't over yet.","TWN":"再忍一下，儀式還沒結束。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"자네야말로 무슨 소리야? 저걸 듣고 가만히 있으려면 뭐하러 기사단에 들어온 건데?","JPN":"君もだぞ？　あれを聞いて落ち着けと言うのか？　君は騎士団に入った理由を忘れたのか？","ENG":"Are you serious? I didn't join the Knights to put up with that kind of crap.","TWN":"你在說什麼？聽到那種話你還能裝作沒事，那幹嘛要進騎士團？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"예식을 주관하시는 분은 무슨 잘못인가. 곧 기회가 올 거야.","JPN":"式の主催側に失礼だろう。もうすぐチャンスが来るさ。","ENG":"Don't blame the officiator. We'll have our opportunity soon enough.","TWN":"主持儀式的人何罪之有？很快就會有機會的。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"칫……!","JPN":"チッ……！","ENG":"Bah...!","TWN":"嗟……！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"우와, 평소에 얼굴 보기 힘들던 평기사 아저씨들이 전부 모였네.","JPN":"わあ、普段なかなか顔も見られない平騎士のおじさんたちも勢ぞろいだね。","ENG":"Whoa, all the knight bachelors are here. This is so rare.","TWN":"哇，平時很難見到的平民騎士大叔們都齊聚一堂欸！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론이죠, 리브 경.","JPN":"そんなこと当たり前でしょう、リブ卿。","ENG":"It is, Dame Liv.","TWN":"那當然囉，莉芙卿。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"새로운 기사단장의 취임식입니다. 기사단의 일원이라면 자신이 갑옷을 입고 있을 때 꼭 참석할 수 있길 바라마지 않을 자리죠.","JPN":"新しい騎士団長の就任式なのです。騎士団の一員なら、鎧を着ている間には参加したいと願ってやまない行事ですからね。","ENG":"Their new captain is being sworn in today. Of course, every member of the Knights wants to be here. While they still get to wear their armor, that is.","TWN":"這可是新任騎士團團長的就任儀式，只要是身為騎士團的一員，都巴不得自己還穿著鎧甲的時候，能有機會參與呢！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 다들 기뻐해야 하는 거 아냐?","JPN":"じゃあ喜ばしいことじゃないの？","ENG":"Then, shouldn't they all be happy?","TWN":"那大家不是應該要開心嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"차기 단장을 저렇게 죽일 듯이 노려보고 있으니까 살벌하다구.","JPN":"みんな次期団長を殺気が満ちた目で睨んでて、殺伐としてるよ。","ENG":"Why are they glaring daggers at their new captain like that?","TWN":"怎麼會眼神像是恨不得要殺掉新任團長似的，充滿肅殺之氣。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"충분히 이해할 수 있는 반응입니다.","JPN":"それは十分理解できます。","ENG":"It's understandable.","TWN":"他們的反應也是完全可以理解的。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"열두 가문의 혈통이 한 방울도 섞이지 않은 자가 두 차례나 연달아 버고 소드의 선택을 받았으니까요.","JPN":"2回連続、12家門の血を一滴も引いてない者がヴァルゴソードに選ばれたのですから。","ENG":"She's the second person in a row who's been chosen by the Virgo Sword from outside the twelve families.","TWN":"因為連續兩次都是完全沒有十二宮血統的人，得到布爾加夫之劍的揀選。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으응? 그렇게 꽉 막힌 아저씨들은 아니지 않았어?","JPN":"ええ？　おじさんたちってそこまで頭の固い人たちだったっけ？","ENG":"What? But I didn't think they were such a narrow-minded lot.","TWN":"嗯？大叔們這麼小心眼喔？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론입니다. 단순히 이례적이라고 해서 원로 분들이 전원 불참하실 정도는 아니죠.","JPN":"いえ。単にそういう理由で元老が全員不参加を決めたわけではありません。","ENG":"They're not. At least not enough for all the Elders to not participate in the ceremony.","TWN":"那當然，如果只是單純的違反常例，元老們也不至於全部缺席。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지 않았다면 전임 기사단장 때도 같은 상황이었을 겁니다.","JPN":"それだけの理由なら、前騎士団長の時もそうしたでしょう。","ENG":"If they were, they would have done the same to the former captain.","TWN":"否則上一任團長的時候，應該也是一樣的情況。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 역시 버고 소드의 선택을 받았을 뿐, 가문과 관련이 없는 사람이었으니까요.","JPN":"彼もまたヴァルゴソードに選ばれただけで、家門とは何の関わりもない人間でしたから。","ENG":"He was also chosen by the Virgo Sword outside the families.","TWN":"他也是受到布爾加夫之劍的揀選而已，但是跟家族完全沒有任何關係。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};